MODEL_PATH = "resume_model (1).pkl" if os.path.exists("resume_model (1).pkl") else "resume_model.pkl"
VEC_PATH = "tfidf_vectorizer (1).pkl" if os.path.exists("tfidf_vectorizer (1).pkl") else "tfidf_vectorizer.pkl"
BUNDLE_PATH = "resume_classifier_bundle.joblib"

model = None
