def train_fallback_model():
    """Train a quick, lightweight fallback model if no weights are found."""
    print("\n[WARNING] No pre-trained model found! Auto-training a fallback model...")
    # Minimal training data covering main categories
    fallback_data = [
        # Data Science
        ("Data Scientist with Python, SQL, machine learning, pandas, scikit-learn, stats, and tensorflow experience.", "Data Science"),
        ("Machine learning engineer specializing in NLP, Deep learning, neural networks, PyTorch and Python data analysis.", "Data Science"),
        # Web Developer / Designing
        ("Frontend Web Developer skilled in HTML, CSS, JavaScript, React, Node.js, and responsive UI design.", "Web Designing"),
        ("Full-stack web engineer. Skilled in React, express.js, MongoDB, bootstrap, frontend and backend development.", "Web Designing"),
        # Java Developer
        ("Java developer with Spring Boot, Hibernate, microservices, Maven, REST APIs, and SQL experience.", "Java Developer"),
        ("Backend software engineer. Expert in Java 11, OOP principles, multithreading, and postgresql database design.", "Java Developer"),
        # HR
        ("HR recruiter specializing in full-cycle recruitment, talent acquisition, employee relations, and onboarding.", "HR"),
        ("Human Resources Manager. Sourced candidates, managed payroll, compliance, and training programs.", "HR"),
        # Accounting
        ("Senior Accountant experienced in auditing, tax declaration, general ledger, invoice reconciliation, and Excel spreadsheets.", "ACCOUNTANT"),
        ("Financial accountant. Handled balance sheet audits, quickbooks accounting, taxation, and budgeting.", "ACCOUNTANT"),
        # Engineering
        ("Mechanical engineer proficient in CAD design, SolidWorks modeling, product manufacturing, and structural analysis.", "ENGINEERING"),
        ("Project engineer. Managed civil engineering construction layouts, manufacturing processes, and technical planning.", "ENGINEERING")
    ]
    
    texts = [clean_resume(item[0]) for item in fallback_data]
    categories = [item[1] for item in fallback_data]
    
    # Train tf-idf and classifier
    vec = TfidfVectorizer(max_features=500, ngram_range=(1, 2))
    X_vec = vec.fit_transform(texts)
    
    clf = LogisticRegression(class_weight="balanced")
    clf.fit(X_vec, categories)
    
    # Save fallback
    joblib.dump(clf, MODEL_PATH)
    joblib.dump(vec, VEC_PATH)
    print("[SUCCESS] Fallback model trained and saved successfully.\n")
    return clf, vec

